 13→interface ProjectsProps {
 14→  onBack: () => void;
 15→  onNavigateToAnalysis: () => void;
 16→  user: User | null;
 17→  history: AnalysisResult[];
 18→  onViewAnalysis: (result: AnalysisResult, tab: 'overview' | 'details' | 'recommendations' | 'preview') => void;
 19→  projectCount: number;
