 30→// Helper to convert AnalysisResult to Project format
 31→const mapAnalysisToProject = (analysis: AnalysisResult, index: number): Project => {
 32→  const hostname = new URL(analysis.url).hostname;
 33→  return {
 34→    id: `proj_${index}_${hostname}`,
 35→    name: hostname,
 36→    domain: analysis.url,
 37→    status: 'active',
 38→    lastRun: analysis.timestamp,
 39→    visibilityScore: analysis.globalScore,
 40→    trend: analysis.globalScore > 70 ? 12 : (analysis.globalScore > 50 ? 5 : -5), // Simulé basé sur le score
 41→    nextRun: new Date(new Date(analysis.timestamp).getTime() + 86400000 * 7).toISOString()
 42→  };
 43→};
 44→
 45→const Projects: React.FC<ProjectsProps> = ({ onBack, onNavigateToAnalysis, user, history, onViewAnalysis, projectCount, maxProjects, onNavigateToPlan, onDeductCredits, onSaveSolution, onNewAnalysis, onNavigateToRecharge, initialUrl, initialTab }) => {
 46→  // Navigation internal state: monitoring | report | action-plan | rescan | archives
 47→  const [activeTab, setActiveTab] = useState<'monitoring' | 'report' | 'action-plan' | 'rescan' | 'archives'>(() => {
 48→    if (initialTab === 'archives') return 'archives';
 49→    if (initialTab === 'recommendations' || initialTab === 'action-plan') return 'action-plan';
 50→    if (initialTab === 'details' || initialTab === 'report') return 'report';
 51→    return 'monitoring';
 52→  });
 53→
 54→  useEffect(() => {
 55→    if (initialTab === 'archives') setActiveTab('archives');
 56→    else if (initialTab === 'recommendations') setActiveTab('action-plan');
 57→    else if (initialTab === 'details' || initialTab === 'report') setActiveTab('report');
 58→    else if (initialTab === 'overview') setActiveTab('monitoring');
 59→  }, [initialTab]);
 60→
 61→  // Use history to build project list, defaulting to mock if empty for demo
 62→  const projects = useMemo(() => {
 63→    if (history.length > 0) {
 64→      // Deduplicate by URL hostname, keeping the most recent
 65→      const uniqueMap = new Map<string, AnalysisResult>();
 66→      history.forEach(item => {
 67→        try {
 68→            const host = new URL(item.url).hostname;
 69→            if (!uniqueMap.has(host) || new Date(item.timestamp) > new Date(uniqueMap.get(host)!.timestamp)) {
 70→                uniqueMap.set(host, item);
 71→            }
 72→        } catch(e) {}
 73→      });
 74→      return Array.from(uniqueMap.values()).map((analysis, index) => mapAnalysisToProject(analysis, index));
 75→    } else {
 76→      // Mock data fallback if no history
 77→      return [
 78→        {
 79→          id: 'demo_1',
 80→          name: 'Exemple Site Demo',
 81→          domain: 'https://demo-site.com',
 82→          status: 'active',
 83→          lastRun: new Date().toISOString(),
 84→          visibilityScore: 45,
 85→          trend: 0,
 86→          nextRun: new Date(Date.now() + 86400000).toISOString()
 87→        }
 88→      ] as Project[];
 89→    }
 90→  }, [history]);
 91→
 92→  const [selectedProjectId, setSelectedProjectId] = useState<string>(() => {
 93→    if (initialUrl && projects.length > 0) {
 94→        try {
 95→            const targetHost = new URL(initialUrl).hostname;
 96→            // The projects mapping uses hostname as name
 97→            const found = projects.find(p => p.name === targetHost);
 98→            if (found) return found.id;
 99→        } catch(e) {}
100→    }
101→    return projects[0]?.id || '';
102→  });
103→
104→  const [selectedAnalysisState, setSelectedAnalysisState] = useState<AnalysisResult | null>(null);
105→  
106→  // States for viewing archive modal
