109→
110→  const currentProject = projects.find(p => p.id === selectedProjectId) || projects[0];
111→  
112→  // Filter history for current project ONLY
113→  const projectHistory = useMemo(() => {
114→    return history
115→      .filter(h => {
116→          try { return new URL(h.url).hostname === currentProject.name; }
