143→    }
144→    
145→    const cats = activeAnalysis.categories;
146→    
147→    // Aggregation logic
148→    const techScore = Math.round(
149→      ((cats['technical']?.score || 0) + (cats['ux']?.score || 0) + (cats['freshness']?.score || 0)) / 3
150→    );
151→    
152→    const semScore = Math.round(
153→      ((cats['semantic']?.score || 0) + (cats['content']?.score || 0) + (cats['geo']?.score || 0) + (cats['media']?.score || 0)) / 4
