259→        onNavigateToAnalysis();
260→    }
261→  };
262→
263→  const handleBackToMonitoring = () => {
264→    setActiveTab('monitoring');
265→  };
266→
267→  const isLimitReached = projectCount >= maxProjects;
268→
269→  // -- SHARED TABS BAR (rendered on all views) --
270→  const [isProjectDropdownOpen, setIsProjectDropdownOpen] = useState(false);
271→
272→  const renderTabsBar = () => (
273→    <div className="w-full px-4 pt-8">
274→      {/* URL Selector — prominent, above tabs */}
275→      <div className="flex flex-col sm:flex-row items-start sm:items-center gap-3 mb-6">
276→        <div className="relative">
277→          <button
278→            onClick={() => setIsProjectDropdownOpen(!isProjectDropdownOpen)}
