  74→// Animated number hook for smooth credit transitions
  75→const useAnimatedNumber = (value: number, duration = 600) => {
  76→  const [display, setDisplay] = useState(value);
  77→  const prevValue = useRef(value);
  78→  useEffect(() => {
  79→    if (prevValue.current === value) return;
  80→    const start = prevValue.current;
  81→    const diff = value - start;
  82→    const startTime = performance.now();
  83→    const animate = (now: number) => {
  84→      const progress = Math.min((now - startTime) / duration, 1);
  85→      const eased = 1 - Math.pow(1 - progress, 3);
  86→      setDisplay(Math.round(start + diff * eased));
  87→      if (progress < 1) requestAnimationFrame(animate);
  88→    };
  89→    requestAnimationFrame(animate);
  90→    prevValue.current = value;
  91→  }, [value, duration]);
  92→  return display;
  93→};
